// Plausible-looking test data for the 4 reference channels — matches
// the real config confirmed earlier: Test(kWh)/Water(liter)/Nitrogen(m3)/
// CO2(liter). Edit CHANNELS below if your own channel setup differs.
const CHANNELS = [
  { channel: 1, name: 'Test (kWh)',    rateMin: 300, rateMax: 2800, cumStep: [0.001, 0.02] },
  { channel: 2, name: 'Water (liter)', rateMin: 0,   rateMax: 40,   cumStep: [0, 0.3] },
  { channel: 3, name: 'Nitrogen (m3)', rateMin: 0,   rateMax: 3,    cumStep: [0, 0.05] },
  { channel: 4, name: 'CO2 (liter)',   rateMin: 0,   rateMax: 15,   cumStep: [0, 0.15] },
];

let state = context.get('counterState');
if (!state) {
    state = {};
    CHANNELS.forEach(c => { state[c.channel] = 0; });
}

const outputs = CHANNELS.map(function(c) {
    const rate = c.rateMin + Math.random() * (c.rateMax - c.rateMin);
    const step = c.cumStep[0] + Math.random() * (c.cumStep[1] - c.cumStep[0]);
    state[c.channel] += step;
    return {
        payload: {
            channel: c.channel,
            cumulative: Math.round(state[c.channel] * 1000) / 1000,
            currentRate: Math.round(rate * 10) / 10,
        },
        topic: c.name,
    };
});

context.set('counterState', state);
return [outputs];
